 930	  }
 931	
 932	  function appendWifiPassword(text) {
 933	    wifiPassword += text;
 934	    wifiMessage = "";
 935	  }
 936	
 937	  function eraseWifiPassword() {
 938	    wifiPassword = wifiPassword.slice(0, -1);
 939	    wifiMessage = "";
 940	  }
 941	
 942	  function syncNetworkSelection() {
 943	    const previousKey = networkSelectedKey;
 944	    if (networkSelectorEntries.length === 0) {
 945	      wifiSelectedIndex = 0;
 946	      networkSelectedKey = "";
 947	      if (previousKey !== "" && wifiPasswordMode) {
 948	        wifiPasswordMode = false;
 949	        wifiPassword = "";
 950	        wifiMessage = "Network no longer available";
 951	      }
 952	      return;
 953	    }
 954	
 955	    const preservedIndex = networkSelectorEntries.findIndex(entry =>
 956	      entry.key === previousKey);
 957	    wifiSelectedIndex = preservedIndex >= 0 ? preservedIndex
 958	      : Math.min(wifiSelectedIndex, networkSelectorEntries.length - 1);
 959	    networkSelectedKey = networkSelectorEntries[wifiSelectedIndex].key;
 960	    if (previousKey !== "" && preservedIndex < 0 && wifiPasswordMode) {
 961	      wifiPasswordMode = false;
 962	      wifiPassword = "";
 963	      wifiMessage = "Network no longer available";
 964	    }
 965	  }
 966	
 967	  function setWifiSelection(index, direction) {
 968	    if (networkSelectorEntries.length === 0)
 969	      return;
 970	    wifiSelectionDirection = direction;
 971	    wifiSelectedIndex = Math.max(0,
 972	      Math.min(index, networkSelectorEntries.length - 1));
 973	    networkSelectedKey = networkSelectorEntries[wifiSelectedIndex].key;
 974	    wifiPasswordMode = false;
 975	    wifiPassword = "";
 976	    wifiMessage = "";
 977	  }
 978	
 979	  function moveWifiSelection(delta) {
 980	    if (networkSelectorEntries.length === 0)
 981	      return;
 982	    setWifiSelection((wifiSelectedIndex + delta + networkSelectorEntries.length)
 983	      % networkSelectorEntries.length, delta >= 0 ? 1 : -1);
 984	  }
 985	
 986	  function finishWifiRefresh() {
 987	    // In Quickshell 0.3, disabling the scanner also hides every unknown,
 988	    // disconnected network. Keep it enabled for the selector's lifetime and
 989	    // stop only the temporary loading indicator here.
 990	    wifiLoading = false;
 991	  }
 992	
 993	  function stopWifiScan() {
 994	    wifiScanTimer.stop();
 995	    if (wifiDevice !== null && wifiDevice.scannerEnabled)
 996	      wifiDevice.scannerEnabled = false;
 997	    wifiLoading = false;
 998	  }
 999	
1000	  function refreshWifiNetworks(silent = false) {
1001	    if (wifiDevice === null) {
1002	      wifiLoading = false;
1003	      if (!silent)
1004	        wifiMessage = "Wi-Fi device unavailable";
1005	      return;
1006	    }
1007	
1008	    if (!silent) {
1009	      wifiLoading = true;
1010	      wifiMessage = "";
1160	  }
1161	
1162	  function finishBluetoothAction(succeeded) {
1163	    bluetoothActionTimer.stop();
1164	    const completedDeviceAddress = bluetoothActionDevice !== null
1165	      ? bluetoothActionDevice.address : bluetoothSelectedAddress;
1166	    if (succeeded) {
1167	      if (bluetoothAction === "pair") {
1168	        if (bluetoothActionDevice !== null)
1169	          bluetoothActionDevice.trusted = true;
1170	        bluetoothTab = 0;
1171	        bluetoothSelectedIndex = 0;
1172	        syncBluetoothSelection(completedDeviceAddress);
1173	        stopBluetoothDiscovery();
1174	      }
1175	      bluetoothSelectorMessage = "";
1176	    } else {
1177	      bluetoothSelectorMessage = "Bluetooth action failed";
1178	    }
1179	    bluetoothActionDevice = null;
1180	    bluetoothAction = "";
1181	  }
1182	
1183	  function wifiIsSecured(network) {
1184	    return network.security !== "" && network.security !== "--"
1185	      && network.security.toLowerCase() !== "open";
1186	  }
1187	
1188	  function connectSelectedWifi() {
1189	    if (networkSelectorEntries.length === 0)
1190	      return;
1191	    const network = networkSelectorEntries[Math.min(wifiSelectedIndex,
1192	      networkSelectorEntries.length - 1)];
1193	    if (network.type === "ethernet" || network.active) {
1194	      hideWifiSelector();
1195	      return;
1196	    }
1197	    if (wifiPendingNetwork !== null)
1198	      return;
1199	
1200	    if (wifiPasswordMode && wifiPassword.length === 0) {
1201	      wifiMessage = "Password required";
1202	      return;
1203	    }
1204	
1205	    if (!wifiPasswordMode && wifiIsSecured(network) && !network.known) {
1206	      wifiPasswordMode = true;
1207	      wifiPassword = "";
1208	      wifiMessage = "";
1209	      return;
1210	    }
1211	
1212	    wifiPendingNetwork = network;
1213	    wifiConnectionUsedPassword = wifiPasswordMode;
1214	    wifiMessage = "Connecting to " + network.ssid + "…";
1215	    wifiConnectionTimer.restart();
1216	
1217	    if (wifiPasswordMode) {
1218	      network.nativeNetwork.connectWithPsk(wifiPassword);
1219	      wifiPassword = "";
1220	      wifiPasswordMode = false;
1221	    } else {
1222	      network.nativeNetwork.connect();
1223	    }
1224	  }
1225	
1350	  }
1351	
