1382	      if (root.wifiPendingNetwork !== null
1383	          && root.wifiPendingNetwork.nativeNetwork.connected) {
1384	        wifiConnectionTimer.stop();
1385	        root.wifiPendingNetwork = null;
1386	        root.wifiConnectionUsedPassword = false;
1387	        root.hideWifiSelector();
1388	      }
1389	    }
1390	
1391	    function onConnectionFailed(reason) {
1392	      root.failWifiConnection();
1393	    }
1394	  }
1395	
1396	  Connections {
1397	    target: root.bluetoothActionDevice
1398	
1399	    function onConnectedChanged() {
1400	      if (root.bluetoothActionDevice === null)
1401	        return;
1402	      if (root.bluetoothAction === "connect" && root.bluetoothActionDevice.connected)
1403	        root.finishBluetoothAction(true);
1404	      else if (root.bluetoothAction === "disconnect"
1405	          && !root.bluetoothActionDevice.connected)
1406	        root.finishBluetoothAction(true);
1407	    }
1408	
1409	    function onPairedChanged() {
1410	      if (root.bluetoothAction === "pair" && root.bluetoothActionDevice !== null
1411	          && root.bluetoothActionDevice.paired)
1412	        root.finishBluetoothAction(true);
1413	    }
1414	  }
