1419	    onTriggered: root.finishWifiRefresh()
1420	  }

text:
  1	import QtQuick
  2	import "Theme.js" as Theme
  3	
  4	FocusScope {
  5	  id: root
  6	
  7	  required property var statusData
  8	  readonly property var selectedNetwork: statusData.networkSelectorEntries.length > 0
  9	    ? statusData.networkSelectorEntries[Math.min(statusData.wifiSelectedIndex,
 10	        statusData.networkSelectorEntries.length - 1)]
 11	    : null
 12	  readonly property string desiredLabelText: {
 13	    if (statusData.wifiMessage !== "") return statusData.wifiMessage;
 14	    if (statusData.wifiPasswordMode) {
 15	      if (statusData.wifiPassword.length === 0) return "Type password…";
 16	      return "•".repeat(statusData.wifiPassword.length) + " ▏";
 17	    }
 18	    if (statusData.wifiLoading) return "Scanning for networks…";
 19	    return selectedNetwork !== null ? selectedNetwork.label : "No networks found";
 20	  }
 21	  property string displayedLabelText: ""
 22	  property bool componentReady: false
 23	  property bool wheelNavigationPending: false
 24	
 25	  implicitWidth: 400
 26	  implicitHeight: 36
 27	
 28	  function signalIcon(strength) {
 29	    if (strength < 26) return "󰤟";
 30	    if (strength < 51) return "󰤢";
 31	    if (strength < 76) return "󰤥";
 32	    return "󰤨";
 33	  }
 34	
 35	  function syncLabel() {
 36	    selectionWheel.stop();
 37	    outgoingLabel.visible = false;
 38	    incomingSlide.y = 0;
 39	    incomingLabel.text = desiredLabelText;
 40	    displayedLabelText = desiredLabelText;
 41	  }
 42	
 43	  function animateLabel() {
 44	    if (desiredLabelText === displayedLabelText)
 45	      return;
 46	    selectionWheel.stop();
 47	    outgoingSlide.y = 0;
 48	    incomingSlide.y = statusData.wifiSelectionDirection > 0 ? 40 : -40;
 49	    outgoingLabel.text = displayedLabelText;
 50	    outgoingLabel.visible = true;
 51	    incomingLabel.text = desiredLabelText;
 52	    displayedLabelText = desiredLabelText;
 53	    selectionWheel.restart();
 54	  }
 55	
 56	  Component.onCompleted: {
 57	    componentReady = true;
 58	    syncLabel();
 59	  }
 60	
 61	  onDesiredLabelTextChanged: {
 62	    if (!componentReady)
 63	      return;
 64	    if (!wheelNavigationPending || !enabled || statusData.wifiPasswordMode
 65	        || statusData.wifiLoading || statusData.wifiMessage !== "")
 66	      syncLabel();
 67	    else
 68	      animateLabel();
 69	  }
 70	
 71	  onEnabledChanged: {
 72	    if (enabled)
 73	      Qt.callLater(() => root.forceActiveFocus());
 74	  }
 75	
 76	  Keys.onPressed: event => {
 77	    if (statusData.wifiPasswordMode) {
 78	      if (event.key === Qt.Key_Escape) {
 79	        statusData.cancelWifiPassword();
 80	      } else if (event.key === Qt.Key_Return || event.key === Qt.Key_Enter) {
 81	        statusData.connectSelectedWifi();
 82	      } else if (event.key === Qt.Key_Backspace) {
 83	        statusData.eraseWifiPassword();
 84	      } else if (event.key === Qt.Key_U && (event.modifiers & Qt.ControlModifier)) {
 85	        statusData.wifiPassword = "";
 86	        statusData.wifiMessage = "";
 87	      } else if (event.text.length > 0
 88	          && !(event.modifiers & (Qt.ControlModifier | Qt.AltModifier | Qt.MetaModifier))) {
 89	        statusData.appendWifiPassword(event.text);
 90	      }
 91	      event.accepted = true;
 92	      return;
 93	    }
 94	
 95	    if (event.key === Qt.Key_J || event.key === Qt.Key_Down
 96	        || event.key === Qt.Key_L || event.key === Qt.Key_Right) {
 97	      wheelNavigationPending = true;
 98	      statusData.moveWifiSelection(1);
 99	      wheelNavigationPending = false;
100	      event.accepted = true;
101	    } else if (event.key === Qt.Key_K || event.key === Qt.Key_Up
102	        || event.key === Qt.Key_H || event.key === Qt.Key_Left) {
103	      wheelNavigationPending = true;
104	      statusData.moveWifiSelection(-1);
105	      wheelNavigationPending = false;
106	      event.accepted = true;
107	    } else if (event.key === Qt.Key_G && !(event.modifiers & Qt.ShiftModifier)) {
108	      wheelNavigationPending = true;
109	      statusData.setWifiSelection(0, -1);
110	      wheelNavigationPending = false;
111	      event.accepted = true;
112	    } else if (event.key === Qt.Key_G && (event.modifiers & Qt.ShiftModifier)) {
113	      wheelNavigationPending = true;
114	      statusData.setWifiSelection(
115	        Math.max(0, statusData.networkSelectorEntries.length - 1), 1);
116	      wheelNavigationPending = false;
117	      event.accepted = true;
118	    } else if (event.key === Qt.Key_R) {
119	      statusData.refreshWifiNetworks();
120	      event.accepted = true;
121	    } else if (event.key === Qt.Key_Return || event.key === Qt.Key_Enter) {
122	      statusData.connectSelectedWifi();
123	      event.accepted = true;
124	    } else if (event.key === Qt.Key_Escape || event.key === Qt.Key_Q) {
125	      statusData.hideWifiSelector();
126	      event.accepted = true;
127	    }
128	  }
129	
130	  Text {
131	    id: wifiIcon
132	    anchors.left: parent.left
133	    anchors.leftMargin: 15
134	    anchors.verticalCenter: parent.verticalCenter
135	    text: {
136	      if (statusData.wifiLoading) return "󰑐";
137	      if (root.selectedNetwork !== null
138	          && root.selectedNetwork.type === "ethernet")
139	        return "󰈀";
140	      if (root.selectedNetwork !== null)
141	        return root.signalIcon(root.selectedNetwork.strength);
142	      return "󰤭";
143	    }
144	    color: Theme.sideNetwork
145	    font.family: "Ubuntu Nerd Font"
146	    font.pixelSize: 17
147	    font.bold: true
148	
149	    RotationAnimator on rotation {
150	      running: statusData.wifiLoading
151	      from: 0
152	      to: 360
153	      duration: 900
154	      loops: Animation.Infinite
155	      onStopped: wifiIcon.rotation = 0
156	    }
157	  }
158	
159	  Rectangle {
160	    id: activeDot
161	    anchors.left: wifiIcon.right
162	    anchors.leftMargin: 13
163	    anchors.verticalCenter: parent.verticalCenter
164	    width: 7
165	    height: 7
166	    radius: 3.5
167	    color: root.selectedNetwork !== null && root.selectedNetwork.active
168	      ? Theme.sideNetwork : Theme.inactive
169	  }
170	
171	  Item {
172	    id: labelViewport
173	    anchors.left: activeDot.right
174	    anchors.leftMargin: 8
175	    anchors.right: wifiStatus.left
176	    anchors.rightMargin: 12
177	    anchors.top: parent.top
178	    anchors.bottom: parent.bottom
179	    clip: true
180	
181	    Text {
182	      id: outgoingLabel
183	      visible: false
184	      width: parent.width
185	      anchors.verticalCenter: parent.verticalCenter
186	      transform: Translate { id: outgoingSlide }
187	      color: Theme.foreground
188	      elide: Text.ElideRight
189	      font.family: "Ubuntu Nerd Font"
190	      font.pixelSize: 14
191	      font.bold: true
192	    }
193	
194	    Text {
195	      id: incomingLabel
196	      width: parent.width
197	      anchors.verticalCenter: parent.verticalCenter
198	      transform: Translate { id: incomingSlide }
199	      color: Theme.foreground
200	      elide: Text.ElideRight
201	      font.family: "Ubuntu Nerd Font"
202	      font.pixelSize: 14
203	      font.bold: true
204	    }
205	  }
206	
207	  ParallelAnimation {
208	    id: selectionWheel
209	    onStopped: outgoingLabel.visible = false
210	
211	    NumberAnimation {
212	      target: outgoingSlide
213	      property: "y"
214	      from: 0
215	      to: statusData.wifiSelectionDirection > 0 ? -40 : 40
216	      duration: 150
217	      easing.type: Easing.InOutCubic
218	    }
219	
220	    NumberAnimation {
221	      target: incomingSlide
222	      property: "y"
223	      from: statusData.wifiSelectionDirection > 0 ? 40 : -40
224	      to: 0
225	      duration: 150
226	      easing.type: Easing.InOutCubic
227	    }
228	  }
229	
230	  Row {
231	    id: wifiStatus
232	    anchors.right: parent.right
233	    anchors.rightMargin: 15
234	    anchors.verticalCenter: parent.verticalCenter
235	    spacing: 8
236	
237	    Text {
238	      text: !statusData.wifiPasswordMode && root.selectedNetwork !== null
239	        && root.selectedNetwork.type === "ethernet" ? "WIRED"
240	        : !statusData.wifiPasswordMode && root.selectedNetwork !== null
241	          && root.selectedNetwork.security !== ""
242	          && root.selectedNetwork.security !== "--" ? "󰌾" : ""
243	      height: 18
244	      verticalAlignment: Text.AlignVCenter
245	      color: Theme.secondary
246	      font.family: "Ubuntu Nerd Font"
247	      font.pixelSize: root.selectedNetwork !== null
248	        && root.selectedNetwork.type === "ethernet" ? 10 : 13
249	    }
250	
251	    Text {
252	      text: statusData.wifiPasswordMode ? "󰌾"
253	        : statusData.networkSelectorEntries.length > 0
254	          ? (statusData.wifiSelectedIndex + 1) + "/"
255	            + statusData.networkSelectorEntries.length
256	          : "0/0"
257	      height: 18
258	      verticalAlignment: Text.AlignVCenter
259	      color: Theme.secondary
260	      font.family: "Ubuntu Nerd Font"
261	      font.pixelSize: 12
262	      font.bold: true
263	    }
264	  }
265	}

